UPDATE events SET 
  description = '<p>Trossamfunnet Naturfolk har gleden av å ønske velkommen til vår første festival i vakre og magiske Sulitjelma (Sulis) i Fauske kommune – gammelt pitesamisk kulturlandskap omgitt av majestetiske fjell, isbreer og fiskerike vann.</p><p>Sulis eller Sulidjælbma er gammelt pitesamisk kulturlandskap og har en historie som fortsatt fortelles av fjellene, vannene og elvene for den som lytter.</p><p>Et gyldenbrun tråd blir bjørnen som mytisk gestalt og åndsvesen i nord. Bjørnen har gjennom årtusener inntatt en særstilling i nordlige urkulturer, og fremstår som et tverrkulturelt mytisk nøkkelmotiv – et kosmisk, sosialt og rituelt bindeledd mellom menneske og natur.</p><p>Programmet byr på seremonier, naturvandringer, foredrag, svettehytteseremoni, sirkler og bålsamlinger. Det er også satt av god tid til å være sammen, til gode samtaler og til å utvikle vårt fellesskap.</p><p>Vi har leid oss inn hos Sulitjelma Turistsenter med hytter, campingplass, storgamme, kafé og badstue. Overnatting i hytter, telt eller bobil. Festivalpass fra kr 2 000,– for medlemmer. NB! Støttemedlemskap på 200 kr i Naturfolk gir medlemspris.</p><p><strong>Priser:</strong></p><ul><li>Hytte, voksen: 3 500,- (medl.) / 4 000,- (ikke-medl.)</li><li>Telt/bobil, voksen: 2 500,- (medl.) / 3 000,- (ikke-medl.)</li><li>Uten overnatting, voksen: 2 000,- (medl.) / 2 500,- (ikke-medl.)</li><li>Barn under 16 år: Gratis (telt/bobil/uten overn.) / 1 000,- (hytte)</li></ul><p>Kontaktperson: Sylvi Katrin Brandsæther, tlf 907 27 655</p><p><a href="https://urfestivalen.no" target="_blank" rel="noopener noreferrer">Les mer på urfestivalen.no</a></p>',
  ticket_link = 'https://form.jotform.com/260396725951062',
  facebook_link = 'https://www.facebook.com/naturfolk.org/'
WHERE id = '88858c16-4d40-4baa-a787-bfd0f2059c3c'